      { id: 's31', number: '31', name: 'Salada Portuguesa', price: '9.50€', ingredients: { pt: 'Alface, tomate, pepino, cebola, mozzarella, azeitonas e molho.', en: 'Lettuce, tomato, cucumber, onions, mozzarella, olives and sauce.', fr: 'Laitue, tomate, concombre, oignon, fromage, olives et sauce.', de: 'Salat, tomate, gurke, zwiebeln, mozzarella, oliven und soße.', es: 'Lechuga, tomate, pepino, cebolla, mozzarella, aceitunas y salsa.' }, image: IMG_SALAD }
