      { id: 'sp60', number: '60', name: 'Rolo de Kebab', price: '9.50€', ingredients: { pt: 'Tortilha com carne kebab, vegetais frescos e molho.', en: 'Kebab roll with fresh vegetables and sauce.', fr: 'Roulé de kebab avec légumes et sauce.', de: 'Kebab-Rolle com Salat und Soße.', es: 'Rollo de kebab con vegetales y salsa.' }, image: IMG_KEBAB_ROLL }
